import { Link } from 'react-router-dom';import { Alert } from '@/components/ui/alert';import { apiErrorMessage } from '@/lib/apiClient';import { useVendorDashboard } from '../api/useVendors';import { SupplierStatistics } from '../components/SupplierStatistics';import { VendorPageSkeleton } from '../components/VendorPageSkeleton';
export const SupplierDashboardPage=()=>{const q=useVendorDashboard();if(q.isLoading)return <VendorPageSkeleton/>;if(q.error||!q.data)return <Alert variant="danger" title="Supplier dashboard unavailable">{apiErrorMessage(q.error)}</Alert>;const d=q.data;const max=Math.max(1,...d.procurement_spend_by_supplier.map(x=>Number(x.amount)));return <div className="space-y-6 text-slate-800 dark:text-slate-100"><header className="flex flex-col gap-3 sm:flex-row sm:items-end sm:justify-between"><div><p className="text-xs font-bold uppercase tracking-[.18em] text-indigo-600 dark:text-indigo-400">Vendor &amp; Supplier Management</p><h1 className="mt-2 text-2xl font-bold">Supplier Dashboard</h1><p className="mt-1 text-sm text-slate-500 dark:text-slate-400">Supplier health, contracts, ratings, and procurement relationships.</p></div><Link to="/vendors/suppliers" className="rounded-lg bg-indigo-600 px-4 py-2 text-sm font-semibold text-white">View Suppliers</Link></header><SupplierStatistics data={d}/><div className="grid gap-6 xl:grid-cols-2"><section className="rounded-xl border border-slate-200 bg-white p-5 dark:border-slate-700 dark:bg-slate-900"><h2 className="font-bold">Top Suppliers</h2><div className="mt-4 space-y-3">{d.top_suppliers.length?d.top_suppliers.map((s,i)=><Link key={s.id} to={`/vendors/suppliers/${s.id}`} className="flex items-center justify-between rounded-lg border border-slate-100 p-3 hover:border-indigo-200 dark:border-slate-800"><div className="flex items-center gap-3"><span className="flex h-8 w-8 items-center justify-center rounded-full bg-indigo-100 text-sm font-bold text-indigo-700">{i+1}</span><div><p className="font-semibold">{s.company_name}</p><p className="font-mono text-xs text-slate-400">{s.supplier_code}</p></div></div><span className="font-bold text-amber-600">★ {Number(s.overall_rating).toFixed(2)}</span></Link>):<p className="text-sm text-slate-500">No supplier reviews yet.</p>}</div></section><section className="rounded-xl border border-slate-200 bg-white p-5 dark:border-slate-700 dark:bg-slate-900"><h2 className="font-bold">Procurement Spend by Supplier</h2><p className="mt-1 text-xs text-slate-500">Currencies are displayed separately; no FX conversion is applied.</p><div className="mt-4 space-y-4">{d.procurement_spend_by_supplier.length?d.procurement_spend_by_supplier.map(s=><div key={`${s.id}-${s.currency}`}><div className="flex justify-between text-sm"><span>{s.company_name}</span><span className="font-semibold tabular-nums">{s.currency} {Number(s.amount).toLocaleString()}</span></div><div className="mt-1 h-2 rounded-full bg-slate-100 dark:bg-slate-800"><div className="h-2 rounded-full bg-indigo-500" style={{width:`${Math.max(3,Number(s.amount)/max*100)}%`}}/></div></div>):<p className="text-sm text-slate-500">No procurement spend yet.</p>}</div></section></div><section className="rounded-xl border border-slate-200 bg-white p-5 dark:border-slate-700 dark:bg-slate-900"><div className="flex items-center justify-between"><h2 className="font-bold">Expiring Contracts</h2><Link to="/vendors/contracts" className="text-sm font-semibold text-indigo-600">View contracts</Link></div><div className="mt-4 grid gap-3 md:grid-cols-2">{d.expiring_contract_items.length?d.expiring_contract_items.map(c=><article key={c.id} className="rounded-lg border border-amber-200 bg-amber-50 p-4 dark:border-amber-900 dark:bg-amber-950/20"><p className="font-mono text-sm font-bold">{c.contract_number}</p><p className="mt-1 text-sm">{c.supplier_name}</p><p className="mt-2 text-xs font-semibold text-amber-700 dark:text-amber-400">{c.days_remaining} days remaining</p></article>):<p className="text-sm text-slate-500">No contracts expire in the next 30 days.</p>}</div></section></div>;};
